#!/bin/bash\n# 项目改造后期配置和开发环境初始化脚本\n\nset -e\n\necho \"🚀 HearClear 项目改造后初始化\"\necho \"================================\"\n\n# 1. 安装 Sentry（可选，用于错误上报）\necho \"\"\necho \"📦 检查 Sentry 支持...\"\nif ! grep -q '@sentry/react-native' package.json; then\n    echo \"  提示：运行以下命令安装 Sentry:\"\n    echo \"  npm install @sentry/react-native\"\nelse\n    echo \"  ✓ Sentry 已安装\"\nfi\n\n# 2. 验证新文件\necho \"\"\necho \"📁 验证新增文件...\"\nfiles_to_check=(\n    \"src/services/logger.ts\"\n    \"src/services/error-reporter.ts\"\n    \"src/services/api-client.ts\"\n    \"src/services/secure-storage.ts\"\n    \"src/services/auth-enhanced.ts\"\n    \"src/services/performance-monitor.ts\"\n    \"src/utils/validators.ts\"\n    \"src/stores/store-utils.ts\"\n    \"src/stores/audio-store-optimized.ts\"\n    \"src/__tests__/test-utils.ts\"\n    \"docs/REFACTORING_GUIDE.md\"\n    \"docs/REFACTORING_SUMMARY.md\"\n)\n\nfor file in \"${files_to_check[@]}\"; do\n    if [ -f \"$file\" ]; then\n        echo \"  ✓ $file\"\n    else\n        echo \"  ✗ $file (未找到)\"\n    fi\ndone\n\n# 3. 运行类型检查\necho \"\"\necho \"🔍 运行 TypeScript 类型检查...\"\nif command -v tsc &> /dev/null; then\n    tsc --noEmit 2>/dev/null || echo \"  ⚠️  有类型错误，请检查\"\nelse\n    echo \"  TypeScript 未安装，跳过\"\nfi\n\n# 4. 运行测试\necho \"\"\necho \"✅ 运行新增的单元测试...\"\nnpm test -- --testPathPattern=\"(api-client|validators)\" --passWithNoTests || true\n\n# 5. 输出环境变量模板\necho \"\"\necho \"⚙️  环境变量配置\"\necho \"  添加到 .env 或 .env.local:\"\necho \"\"\necho \"  # Sentry (可选)\"\necho \"  SENTRY_DSN=https://your-sentry-dsn@sentry.io/your-project-id\"\necho \"  SENTRY_ENV=production\"\necho \"\"\n\n# 6. 输出快速开始\necho \"📚 快速开始\"\necho \"  1. 运行项目: npm start\"\necho \"  2. 查看改造指南: docs/REFACTORING_GUIDE.md\"\necho \"  3. 查看改造总结: docs/REFACTORING_SUMMARY.md\"\necho \"  4. 运行所有测试: npm test\"\necho \"  5. 生成覆盖率: npm run test:coverage\"\necho \"\"\n\necho \"✨ 初始化完成！\"\necho \"================================\"\n"